+\begin{lemma}
+[Structural consequences of projectivity]
+  \label{lem:projective_with_structural}
+  \leanok
+  \lean{AlgebraicGeometry.Scheme.Hom.IsProjectiveWith.locallyOfFiniteType,
+    AlgebraicGeometry.Scheme.Hom.IsProjectiveWith.isSeparated,
+    AlgebraicGeometry.Scheme.Hom.IsProjectiveWith.universallyClosed}
+  \uses{lem:projective_with_proper}
+  A projective morphism carrying a line bundle is locally of finite type,
+  separated, and universally closed.
+\end{lemma}
+
+\begin{proof}
+  \leanok
+  \uses{lem:projective_with_proper}
+  Immediate from \Cref{lem:projective_with_proper}: properness of a morphism
+  entails that it is locally of finite type, separated, and universally
+  closed.
+\end{proof}
+
+\begin{lemma}
+[Invariance under isomorphism of the bundle]
+  \label{lem:projective_with_iso}
+  \leanok
+  \lean{AlgebraicGeometry.Scheme.Hom.IsProjectiveWith.of_iso}
+  \uses{def:projective_with}
+  If \(\pi : X \to S\) is projective carrying \(L\) and \(L \cong L'\), then
+  \(\pi\) is projective carrying \(L'\).
+\end{lemma}
+
+\begin{proof}
+  \leanok
+  The witnessing closed immersion and its comparison
+  \(L \cong i^* \mathcal{O}(1)\) are unchanged; precompose the comparison with
+  the given isomorphism \(L' \cong L\) to obtain \(L' \cong i^*
+  \mathcal{O}(1)\).
+\end{proof}
